-- Migration 014: Superuser Role Support
-- Run with: psql -U hwchat -d hwchat -f migrations/014_superuser_role.sql
-- Then restart PHP: systemctl restart ea-php82-php-fpm ea-php83-php-fpm

-- 1. Add role column to tenants table
ALTER TABLE tenants
    ADD COLUMN IF NOT EXISTS role TEXT NOT NULL DEFAULT 'tenant_admin'
    CHECK (role IN ('superadmin', 'tenant_admin'));

-- 2. Create superadmin account
