-- You MUST generate the real hash on the server. Run this on the server:
--   php -r "echo password_hash('HWSuper2026!', PASSWORD_BCRYPT);"
-- Then replace the placeholder below with the output.

INSERT INTO tenants (
    id, email, password_hash, display_name, role,
    system_prompt, community_type, is_active
) VALUES (
