    'admin@hillwoodcommunities.com',
    '$2y$10$5Q1lyXY/iNtC.FHCrWbTt.no8cwjdc/gd9YouzGKeSPa7bl3Rp/2a',  -- REPLACE with output of: php -r "echo password_hash('HWSuper2026!', PASSWORD_BCRYPT);"
