-- 3. Ensure existing tenants are explicitly tenant_admin
UPDATE tenants SET role = 'tenant_admin' WHERE role IS NULL OR role = '';

-- 4. Add global_settings entries for community directory (future use)
INSERT INTO global_settings (key, value)
VALUES ('community_directory', '{}')
ON CONFLICT (key) DO NOTHING;
